import { GoldRushClient } from "@covalenthq/client-sdk";

const client = new GoldRushClient(process.env.GOLDRUSH_API_KEY);

async function getDAOVoterIntelligence(chainName, govContractAddress, walletAddress) {
  const events = await client.BaseService.getLogEventsByAddress(
    chainName, govContractAddress, { startingBlock: "earliest" }
  );
  const votes = (events.data?.items ?? []).filter(e =>
    e.decoded?.name === "VoteCast" &&
    e.decoded?.params?.find(p => p.name === "voter")?.value === walletAddress
  );
  return { totalVotes: votes.length, votes };
}
